    vector<long long> prefix_L(n + 1, 0);
    for (int i = 0; i < n; ++i) {
        prefix_L[i+1] = prefix_L[i] + (s[i] == 'L' ? 1 : 0);
    }

    vector<long long> suffix_C(n + 1, 0);
    for (int i = n-1; i >= 0; --i) {
        suffix_C[i] = suffix_C[i+1] + (s[i] == 'C' ? 1 : 0);
    }

    vector<long long> suffix_T(n + 1, 0);
    for (int i = n-1; i >= 0; --i) {
        suffix_T[i] = suffix_T[i+1] + (s[i] == 'T' ? 1 : 0);
    }

    long long original = 0;
    for (int i = 0; i < n; ++i) {
        if (s[i] == 'C') {
            original += prefix_L[i] * suffix_T[i+1];
        }
    }

    vector<long long> sum_c_t(n + 1, 0);
    for (int i = n-1; i >= 0; --i) {
        if (s[i] == 'C') {
            sum_c_t[i] = suffix_T[i+1] + sum_c_t[i+1];
        } else {
            sum_c_t[i] = sum_c_t[i+1];
        }
    }

    long long max_insert_L = 0;
    for (int i = 0; i <= n; ++i) {
        if (sum_c_t[i] > max_insert_L) {
            max_insert_L = sum_c_t[i];
        }
    }

    long long max_insert_C = 0;
    for (int i = 0; i <= n; ++i) {
        long long current = prefix_L[i] * suffix_T[i+1];
        if (current > max_insert_C) {
            max_insert_C = current;
        }
    }

    vector<long long> sum_c_l(n + 1, 0);
    for (int i = 1; i <= n; ++i) {
        sum_c_l[i] = sum_c_l[i-1] + (s[i-1] == 'C' ? prefix_L[i-1] : 0);
    }

    long long max_insert_T = 0;
    for (int i = 0; i <= n; ++i) {
        if (sum_c_l[i] > max_insert_T) {
            max_insert_T = sum_c_l[i];
        }
    }

    long long ans = original + max(max_insert_L, max_insert_C, max_insert_T);
    return ans;
}
